const browser = (window.chrome) ? window.chrome : window.browser

const totalDayMS = 24 * 60 * 60 * 1000;
let dateFormat = "YYYY-MM-DD";
let timeFormat = "HH:mm:ss A";

const colors = {
    bg: "#222222",
    font: "#FFFFFF",
    shadow: "rgba(255, 255, 255, 0.3)"
}


function GetTime() {
    const prettyTime = moment().format(timeFormat);
    document.getElementById('clockbox').innerHTML = prettyTime
}
function GetDate() {
    const dayOfWeek = moment().format('dddd');
    const prettyDate = moment().format(dateFormat);
    document.getElementById('daybox').innerHTML = dayOfWeek;
    document.getElementById('datebox').innerHTML = prettyDate
}
function CheckDayCountdown() {
    if ($("#workday-checkbox").is(":checked")) {
        browser.storage.sync.set({ 'user-use-workday': 'true' });
        CountdownWorkday()
    }
    else {
        browser.storage.sync.set({ 'user-use-workday': 'false' });
        CountdownDay()
    }
}
function CountdownDay() {
    const now = new Date();
    const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    const progressMS = now - todayStart;
    const progressPCT = progressMS / totalDayMS * 100;
    const prettyPCT = Math.round(progressPCT);
    $("#countdown-day .countdown-label").replaceWith("<div class='countdown-label'>...of the day</div>");
    document.getElementById('countdown-day-amount').innerHTML = prettyPCT + "%"
}
function CountdownWorkday() {
    //var workdayStartString, workdayEndString, workdayStartHour, workdayStartMin, workdayEndHour, workdayEndMin, progressPCT;


    browser.storage.sync.get(['user-workday-start', 'user-workday-end'], function (retrieved) {
        const workdayStartString = retrieved['user-workday-start'] ? retrieved['user-workday-start'] : "09:00";
        const workdayEndString = retrieved['user-workday-end'] ? retrieved['user-workday-end'] : "18:00";
        const workdayStartHour = workdayStartString.split(":")[0];
        const workdayStartMin = workdayStartString.split(":")[1];
        const workdayEndHour = workdayEndString.split(":")[0];
        const workdayEndMin = workdayEndString.split(":")[1];

        const now = new Date();
        const workdayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate(), parseInt(workdayStartHour), parseInt(workdayStartMin));
        const workdayEnd = new Date(now.getFullYear(), now.getMonth(), now.getDate(), parseInt(workdayEndHour), parseInt(workdayEndMin));
        if (now < workdayStart) {
            progressPCT = 0
        } else if (now > workdayEnd) {
            progressPCT = 100
        } else {
            var progressMS = now - workdayStart, totalDayMS = workdayEnd - workdayStart;
            progressPCT = progressMS / totalDayMS * 100
        }
        const prettyPCT = Math.round(progressPCT);
        $("#countdown-day .countdown-label").replaceWith("<div class='countdown-label'>...of the workday</div>");
        document.getElementById('countdown-day-amount').innerHTML = prettyPCT + "%"
    })
}
function CountdownMonthYear() {
    const now = new Date();
    const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);
    const progressMonthMS = now - monthStart;
    const totalMonthMS = moment().daysInMonth() * totalDayMS;
    const monthProgressPCT = progressMonthMS / totalMonthMS * 100;
    const prettyMonthPCT = Math.round(monthProgressPCT);
    const yearStart = new Date(now.getFullYear(), 0, 1);
    const progressYearMS = now - yearStart;
    const totalYearMS = 365 * totalDayMS;
    const yearProgressPCT = progressYearMS / totalYearMS * 100;
    const prettyYearPCT = Math.floor(yearProgressPCT);

    document.getElementById('countdown-month-amount').innerHTML = prettyMonthPCT + "%";
    document.getElementById('countdown-year-amount').innerHTML = prettyYearPCT + "%";
    setTimeout(CountdownMonthYear, 1000)
}
$(document).click(function (event) {
    if (!$(event.target).closest('#customize-corner').length) {
        if ($('#customize-corner').is(":visible")) {
            $('#customize-selectors').hide();
            $('#customize-button').fadeIn()
        }
    }

    const listClassSuffixes = ["left", "mid", "right"];
    for (const suffix of listClassSuffixes) {
        if (!$(event.target).closest(`#list-${suffix}`).length) {
            if ($(`#list-${suffix} .edit-priorities`).is(":visible")) {
                $(`#list-${suffix} .edit-priorities`).hide();
                $(`#list-${suffix} .edit-priorities-link`).show()
            }
        }
    }
});

function SetColorProperty(classes, propToChange, newValue) {
    //const style = $('<style>.' + classToChange + ' { ' + propToChange + ': ' + newValue + '; }</style>');

    const selectors = Array.isArray(classes) ? classes.map(c => `.${c}`).join(", ") : `.${classes}`
    //console.log("selectors", selectors)
    const style = $(`<style>${selectors} { ${propToChange}: ${newValue}; } </style>`);
    $('html > head').append(style);
}


function SetColors() {
    browser.storage.sync.get('user-background-color',
        function (result) {
            const bgColor = (result['user-background-color']) ? result['user-background-color'] : colors.bg;
            SetColorProperty('main-bg-color', 'background-color', bgColor)
        });
    browser.storage.sync.get('user-font-color',
        function (result) {
            const fontColor = (result['user-font-color']) ? result['user-font-color'] : colors.font;
            SetColorProperty(['main-font-color', 'main-border-color'], 'color', fontColor)
        });
    browser.storage.sync.get('user-shadow-color',
        function (result) {
            const shadowColor = (result['user-shadow-color']) ? result['user-shadow-color'] : colors.shadow;
            SetColorProperty(['shadow-color', 'shadow-border-color'], 'color', shadowColor);
        })
}

function SetDateTimeFormat() {
    browser.storage.sync.get({ 'user-date-format': "MMM D, YYYY" },
        function (result) {
            dateFormat = result['user-date-format'];
            GetDate();
            $('#date-format-input').val(dateFormat)
        });
    browser.storage.sync.get({ 'user-time-format': "h:mm:ss A" },
        function (result) {
            timeFormat = result['user-time-format'];
            GetTime();
            $('#time-format-input').val(timeFormat)
        })
}

function createColorPickerInstance(
    buttonID, // The color picker is launched when the button specified is clicked
    defaultColor, // Ideally is fetched from the colors obj
    cssClasses, // An array of strings (or a string) of class names for the chosen color to be applied onto
    storageSyncKey, // The key to store the chosen color in Google (or Firefox) cloud
    isBackgroundColor = false
) {

    const buttonIDSelector = (buttonID.startsWith("#")) ? buttonID : `#${buttonID}`
    const inst = $(buttonIDSelector).colpick({
        layout: 'full', submit: !1, colorScheme: 'dark', color: defaultColor,
        onChange: function (hsb, hex, rgb, el, bySetColor) {
            const propType =  isBackgroundColor ? 'background-color' : 'color'
            SetColorProperty(cssClasses, propType, `#${hex}`);
            browser.storage.sync.set({ [storageSyncKey]: `#${hex}`})
        },
        onHide: function (cpobj) {
            $('.color-selector-label').css('visibility', 'visible');
            $('.color-selector-label').css('font-weight', 'normal')
        }
    });

    return inst;

}

window.onload = function () {
    var el = document.querySelector('body');
    $('#verborgen_file').hide();
    $('#uploadButton').on('click', function () {
        $('#verborgen_file').click();
    });

    $('#verborgen_file').change(function () {
        const file = this.files[0];
        const reader = new FileReader();
        reader.onloadend = function () {
            browser.storage.local.set({ "user_bg_img": reader.result }, function () {
                console.log("set");
            })
            $('body').css('background-image', 'url("' + reader.result + '")');
        }
        if (file) {
            reader.readAsDataURL(file);
        } else {
        }
    });
    browser.storage.local.get(["user_bg_img"], function (item) {
        //$('body').css('background-image', 'url("' + item["user_bg_img"] + '")');
        el.style.backgroundImage = 'url(' + item["user_bg_img"] + ')';
    });

    localStorage.setCentered == 'center' && $('body').css('background-position', 'center center');

    $('#centerImgBackground').on('click', function () {
        localStorage.setCentered == 'center' ?
            ($('body').css('background-position', 'unset'),
                localStorage.setCentered = 'unset') :
            ($('body').css('background-position', 'center center'),
                localStorage.setCentered = 'center');
    });
    SetDateTimeFormat();
    browser.storage.sync.get('user-use-workday', function (result) {
        if (result['user-use-workday'] === "true") {
            CountdownWorkday();
            $("#workday-checkbox").prop("checked", !0)
        }
        else {
            CountdownDay()
        }
    });
    CountdownMonthYear();
    setInterval(GetTime, 1000);
    setInterval(CountdownDay, 900000);
    SetColors();
    browser.storage.sync.get('update-20151231', function (result) {
        if (!result['update-20151231']) {
            $("#update-footer").fadeIn(500).fadeOut(500).fadeIn(500);
            browser.storage.sync.set({ 'update-20151231': !0 })
        }
    });
    $("#update-hide").click(function (e) {
        $("#update-footer").hide();
        browser.storage.sync.set({ 'update-20151231': !0 })
    });

    browser.storage.sync.get(['user-workday-start', 'user-workday-end'], function (retrieved) {
        workdayStart = retrieved['user-workday-start'] ? retrieved['user-workday-start'] : "09:00";
        workdayEnd = retrieved['user-workday-end'] ? retrieved['user-workday-end'] : "18:00";
        $("#workday-start-timeinput")[0].value = workdayStart;
        $("#workday-end-timeinput")[0].value = workdayEnd
    });
    $('.edit-priorities-link').click(function (e) {
        $('.edit-priorities').each(function (index) {
            $(this).hide();
            $(this).siblings('.edit-priorities-link').fadeIn()
        });
        $(this).hide();
        prioritiesList = $(this).siblings('.edit-priorities')[0];
        $(prioritiesList).fadeIn();
        $(prioritiesList).find('input.todo').focus()
    });
    $('.hide-edit').click(function (e) {
        $(this).parent().hide();
        $(this).parent().siblings('.edit-priorities-link').show()
    });
    $('#info-corner').hover(function () {
        $(this).children('#info-button').hide();
        $(this).children('#info').fadeIn()
    }, function () {
        $(this).children('#info').hide();
        $(this).children('#info-button').fadeIn()
    });
    $('#customize-button').click(function () {
        $('#customize-button').hide();
        $('#customize-selectors').fadeIn()
    });
    $('#hide-customize-selectors').click(function () {
        $('#customize-selectors').hide();
        $('#customize-button').fadeIn()
    });

    createColorPickerInstance('#background-color-selector', colors.bg, 'main-bg-color', 'user-background-color', true);
    createColorPickerInstance('#font-color-selector', colors.font, ['main-font-color', 'main-border-color'], 'user-font-color');
    createColorPickerInstance('#shadow-color-selector', colors.shadow, ['shadow-color', 'shadow-border-color'], 'user-shadow-color');


    $('.customize-selector-label').click(function (e) {
        $(this).siblings('.color-selector-label').css('visibility', 'hidden');
        $(this).show();
        $(this).css('font-weight', 'bold')
    });


    $('#restore-default-colors').click(function (e) {
        // TODO: Simplify this
        SetColorProperty('main-bg-color', 'background-color', colors.bg);
        browser.storage.sync.set({ 'user-background-color': colors.bg });
        SetColorProperty(['main-font-color', 'main-border-color'], 'color', colors.font);
        browser.storage.sync.set({ 'user-font-color': colors.font });
        SetColorProperty(['shadow-color', 'shadow-border-color'], 'color', colors.shadow);
        browser.storage.sync.set({ 'user-shadow-color': colors.shadow })

    });
    $('#workday-checkbox').click(function (e) { CheckDayCountdown() });
    $("#workday-time-save").click(function (e) {
        const workdayStart = $("#workday-start-timeinput")[0].value;
        const workdayEnd = $("#workday-end-timeinput")[0].value;
        browser.storage.sync.set({ 'user-workday-start': workdayStart, 'user-workday-end': workdayEnd });
        CheckDayCountdown()
    });
    $("#date-time-format-save").click(function (e) {
        dateFormat = $("#date-format-input option:selected").text();
        timeFormat = $("#time-format-input option:selected").text();
        browser.storage.sync.set({ 'user-time-format': timeFormat });
        browser.storage.sync.set({ 'user-date-format': dateFormat });

        GetDate();
        GetTime()
    });
    // Most likely put function to set background here
    $("#removeBackgroundImg").click(function (e) {
        document.body.style.backgroundImage = 'url(' + null + ')';
        browser.storage.local.set({ "user_bg_img": null });
    })

    $("#uninstall-extension-button").click(function (e) {
        browser.management.uninstallSelf({ showConfirmDialog: !0 })
    })
}
